-- ═══════════════════════════════════════════════════════════
-- 1. ADD UNIQUE CONSTRAINT ON fondos.isin (if not exists)
-- ═══════════════════════════════════════════════════════════
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname='fondos_isin_key') THEN
    ALTER TABLE fondos ADD CONSTRAINT fondos_isin_key UNIQUE (isin);
  END IF;
END $$;

